:root {
    --primary-color: #2563eb;
    --secondary-color: #60a5fa;
    --background-color: #ffffff;
    --text-color: #0f172a;
    --card-bg: #f8fafc;
    --border-color: #e2e8f0;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background-color: var(--background-color);
    color: var(--text-color);
    margin: 0;
    padding: 0;
    line-height: 1.6;
    transition: all 0.3s ease;
}

.nav-header {
    position: sticky;
    top: 0;
    background: var(--background-color);
    box-shadow: 0 2px 8px rgba(37, 99, 235, 0.1);
    z-index: 100;
}

.nav-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem 2rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.nav-logo h1 {
    color: var(--primary-color);
    font-size: 1.5rem;
    font-weight: 700;
}

.nav-menu {
    display: flex;
    list-style: none;
    gap: 2rem;
    margin: 0;
    padding: 0;
}

.nav-menu a {
    color: var(--text-color);
    text-decoration: none;
    font-weight: 500;
    transition: color 0.2s;
}

.nav-menu a:hover {
    color: var(--primary-color);
}

#app {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem;
}

#hero {
    text-align: center;
    margin-bottom: 3rem;
}

#hero h2 {
    color: var(--primary-color);
    font-size: 2.5rem;
    margin-bottom: 1rem;
    font-weight: 700;
}

#hero p {
    color: var(--text-color);
    font-size: 1.2rem;
    margin-bottom: 2rem;
    opacity: 0.8;
}

.countdown-timer {
    color: var(--secondary-color);
    font-size: 1.3rem;
    font-weight: 600;
    margin-bottom: 2rem;
}

.sales-banner {
    background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
    color: white;
    padding: 1rem 2rem;
    border-radius: 25px;
    font-weight: 600;
    font-size: 1.1rem;
    display: inline-block;
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.8; }
}

.product-banner {
    background: var(--background-color);
    border: 1px solid var(--border-color);
    border-radius: 16px;
    padding: 2rem;
    margin: 2rem 0;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
    transition: transform 0.3s, box-shadow 0.3s;
}

.product-banner:hover {
    transform: translateY(-4px);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.1);
}

.product-info h3 {
    color: var(--primary-color);
    margin-bottom: 1rem;
    font-size: 1.8rem;
    font-weight: 700;
}

.product-info p {
    color: var(--text-color);
    margin-bottom: 1.5rem;
    opacity: 0.9;
}

.product-price {
    color: var(--secondary-color);
    font-size: 2rem;
    font-weight: 700;
    margin-bottom: 1.5rem;
}

.buy-button {
    background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
    color: white;
    border: none;
    padding: 1rem 2rem;
    border-radius: 50px;
    font-size: 1.1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 4px 15px rgba(37, 99, 235, 0.3);
}

.buy-button:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(37, 99, 235, 0.4);
}

.main-footer {
    background: var(--card-bg);
    border-top: 1px solid var(--border-color);
    margin-top: 4rem;
    padding: 3rem 2rem;
}

.footer-content {
    max-width: 1200px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 2rem;
    padding-bottom: 2rem;
    border-bottom: 1px solid var(--border-color);
}

.footer-section h3,
.footer-section h4 {
    color: var(--primary-color);
    margin-bottom: 1rem;
    font-weight: 600;
}

.footer-section p,
.footer-section ul {
    color: var(--text-color);
    opacity: 0.7;
    margin: 0;
    padding: 0;
}

.footer-section ul {
    list-style: none;
}

.footer-section ul li {
    margin-bottom: 0.5rem;
}

.footer-section a {
    color: var(--text-color);
    text-decoration: none;
    opacity: 0.7;
    transition: opacity 0.2s;
}

.footer-section a:hover {
    opacity: 1;
}

.footer-bottom {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem 0 0;
    text-align: center;
    color: var(--text-color);
    opacity: 0.7;
}

@media (max-width: 768px) {
    .nav-container {
        padding: 1rem;
    }

    .nav-menu {
        gap: 1rem;
        font-size: 0.9rem;
    }

    #app {
        padding: 1rem;
    }

    #hero h2 {
        font-size: 2rem;
    }

    .sales-banner {
        font-size: 1rem;
        padding: 0.75rem 1.5rem;
    }

    .countdown-timer {
        font-size: 1.1rem;
    }

    .product-banner {
        padding: 1.5rem;
    }

    .product-info h3 {
        font-size: 1.5rem;
    }

    .product-price {
        font-size: 1.5rem;
    }

    .buy-button {
        padding: 0.8rem 1.5rem;
        font-size: 1rem;
    }

    .footer-content {
        grid-template-columns: 1fr;
        text-align: center;
    }
}
